import { useState } from 'react'
import { Outlet, Navigate } from 'react-router-dom'
import { useAuth } from '@/contexts/auth-context'
import { Sidebar } from './sidebar'
import { Header } from './header'

export function DashboardLayout() {
  const { isAuthenticated, loading } = useAuth()
  const [sidebarOpen, setSidebarOpen] = useState(false)

  if (loading) {
    return (
      <div className="flex h-screen items-center justify-center">
        <div className="flex flex-col items-center gap-3">
          <div className="h-8 w-8 animate-spin rounded-full border-2 border-primary border-t-transparent" />
          <p className="text-sm text-muted-foreground">Loading...</p>
        </div>
      </div>
    )
  }

  if (!isAuthenticated) {
    return <Navigate to="/login" replace />
  }

  return (
    <div className="flex h-screen overflow-hidden">
      <Sidebar open={sidebarOpen} onClose={() => setSidebarOpen(false)} />
      <div className="flex flex-1 flex-col overflow-hidden">
        <Header onMenuToggle={() => setSidebarOpen(!sidebarOpen)} />
        <main className="flex-1 overflow-y-auto bg-muted/30 p-4 lg:p-6">
          <Outlet />
        </main>
      </div>
    </div>
  )
}

import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import { useAuth } from '@/contexts/auth-context'
import { apiCall } from '@/lib/api'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import {
  Briefcase,
  Users,
  FileText,
  Calendar,
  TrendingUp,
  ArrowRight,
  Plus,
  CreditCard,
  UserCheck,
  BarChart3,
} from 'lucide-react'

interface DashboardStats {
  activeJobs: number
  totalApplications: number
  pendingInterviews: number
  hiredThisMonth: number
}

export function RecruiterDashboard() {
  const { user } = useAuth()
  const [stats, setStats] = useState<DashboardStats>({
    activeJobs: 0,
    totalApplications: 0,
    pendingInterviews: 0,
    hiredThisMonth: 0,
  })
  const [recentApps, setRecentApps] = useState<Array<{
    id: number
    candidate_name: string
    job_title: string
    status: string
    created_at: string
  }>>([])
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    async function loadDashboard() {
      try {
        const [jobsRes, appsRes] = await Promise.allSettled([
          apiCall<{ jobs: Array<unknown> }>('/recruiter/jobs'),
          apiCall<{ applications: Array<{ id: number; candidate_name: string; job_title: string; status: string; created_at: string }> }>('/recruiter/applications?limit=5'),
        ])

        if (jobsRes.status === 'fulfilled') {
          setStats(prev => ({ ...prev, activeJobs: jobsRes.value.jobs?.length || 0 }))
        }
        if (appsRes.status === 'fulfilled') {
          const apps = appsRes.value.applications || []
          setRecentApps(apps.slice(0, 5))
          setStats(prev => ({ ...prev, totalApplications: apps.length }))
        }
      } catch {
        // Best-effort
      } finally {
        setLoading(false)
      }
    }

    loadDashboard()
  }, [])

  const quickActions = [
